index e9e3a0c1..b9e4e65b 100644
--- a/tests/AGENTS.md
+++ b/tests/AGENTS.md
@@ -63,3 +63,15 @@ Each subdirectory under `tests/acceptance/` runs as a separate CI matrix job (se
 - External processes (OpenCode spawn) — mock the handle, not the process
 - Everything else is real internal logic — no mocking internal modules at acceptance level
 - Unit tests may mock dependencies via dependency injection (function parameters)
+
+## `mock.module` Must Preserve Full Export Surface
+
+- Bun's `mock.module` replaces the entire module for all test files sharing the same worker. A partial mock (only exporting the overridden function) strips every other export, causing `SyntaxError: Export named '...' not found` in concurrent test files that import from the same module.
+- Always capture the real module **before** mocking, then spread its exports:
+  ```ts
+  const realModule = await import("../../path/to/module");
+  mock.module("../../path/to/module", () => ({
+    ...realModule,
+    targetFunction: mockFn,
+  }));
+  ```
diff --git a/tests/unit/intent-context.test.ts b/tests/unit/intent-context.test.ts
index 325fca51..c565721e 100644
--- a/tests/unit/intent-context.test.ts
+++ b/tests/unit/intent-context.test.ts
@@ -37,8 +37,13 @@ const WORKSPACE_OVERVIEW = {

 // ---------------------------------------------------------------------------
 // Module mocks — must precede dynamic import of module under test
+// Capture real modules BEFORE mocking so other test files sharing the bun
+// worker keep the full export surface.
 // ---------------------------------------------------------------------------

+const realQueries = await import("../../app/src/server/graph/queries");
+const realEmbeddings = await import("../../app/src/server/graph/embeddings");
+
 const mockBuildTaskContext = mock(() => Promise.resolve(TASK_CONTEXT));
 const mockBuildProjectContext = mock(() => Promise.resolve(PROJECT_CONTEXT));
 const mockBuildWorkspaceOverview = mock(() => Promise.resolve(WORKSPACE_OVERVIEW));
@@ -52,10 +57,12 @@ mock.module("../../app/src/server/mcp/context-builder", () => ({
 }));

 mock.module("../../app/src/server/graph/queries", () => ({
+  ...realQueries,
   searchEntitiesByEmbedding: mockSearchEntitiesByEmbedding,
 }));

 mock.module("../../app/src/server/graph/embeddings", () => ({
+  ...realEmbeddings,
   createEmbeddingVector: mockCreateEmbeddingVector,
 }));

